import hashlib
import json
from functools import wraps
from typing import Any, Callable, Dict, Optional

class ToolLoopGuard:
    def __init__(self, max_duplicate_calls: int = 2, max_total_calls: int = 50):
        self.call_fingerprints: Dict[str, int] = {}
        self.total_calls = 0
        self.max_duplicate_calls = max_duplicate_calls
        self.max_total_calls = max_total_calls

    def _fingerprint(self, tool_name: str, kwargs: dict) -> str:
        payload = json.dumps({"tool": tool_name, "args": kwargs}, sort_keys=True)
        return hashlib.sha256(payload.encode()).hexdigest()

    def check_and_record(self, tool_name: str, kwargs: dict) -> Optional[str]:
        """Returns an error message if the call should be blocked, else None."""
        self.total_calls += 1
        if self.total_calls > self.max_total_calls:
            return f"Tool call budget exceeded ({self.max_total_calls} calls). Task aborted to prevent runaway execution."

        fp = self._fingerprint(tool_name, kwargs)
        count = self.call_fingerprints.get(fp, 0) + 1
        self.call_fingerprints[fp] = count

        if count > self.max_duplicate_calls:
            return (
                f"Duplicate tool call detected: '{tool_name}' has been called with "
                f"identical arguments {count} times. This indicates a reasoning loop. "
                f"You must try a different approach or conclude that this action cannot "
                f"produce new information."
            )
        return None

    def reset(self):
        self.call_fingerprints.clear()
        self.total_calls = 0


def with_loop_guard(guard: ToolLoopGuard):
    """Decorator to wrap tool functions with loop detection."""
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs) -> Any:
            error = guard.check_and_record(func.__name__, kwargs)
            if error:
                # Return the error as a tool result so the LLM can reason about it
                return {"error": error, "status": "blocked_by_loop_guard"}
            return func(*args, **kwargs)
        return wrapper
    return decorator


# Usage example
guard = ToolLoopGuard(max_duplicate_calls=2, max_total_calls=30)

@with_loop_guard(guard)
def fetch_url(url: str) -> dict:
    # ... actual implementation
