from dataclasses import dataclass, field
from typing import Any, List, Optional
import time

@dataclass
class AgentStep:
    step_number: int
    tool_name: str
    tool_args: dict
    tool_result: Any
    timestamp: float = field(default_factory=time.time)

class BudgetedAgentRunner:
    def __init__(
        self,
        agent,
        max_steps: int = 20,
        max_duration_seconds: float = 120.0
    ):
        self.agent = agent
        self.max_steps = max_steps
        self.max_duration_seconds = max_duration_seconds
        self.steps: List[AgentStep] = []
        self.start_time: Optional[float] = None

    def _is_budget_exceeded(self) -> Optional[str]:
        if len(self.steps) >= self.max_steps:
            return f"Step budget exhausted after {self.max_steps} steps."
        elapsed = time.time() - self.start_time
        if elapsed > self.max_duration_seconds:
            return f"Time budget exhausted after {elapsed:.1f}s."
        return None

    def _generate_partial_result(self, task: str, reason: str) -> dict:
        """Produce a useful partial result when the budget is exceeded."""
        completed_tools = list({s.tool_name for s in self.steps})
        last_results = [
            {"tool": s.tool_name, "result": s.tool_result}
            for s in self.steps[-3:]  # Last 3 steps for context
        ]
        return {
            "status": "incomplete",
            "reason": reason,
            "task": task,
            "steps_taken": len(self.steps),
            "tools_used": completed_tools,
            "last_results": last_results,
            "recommendation": (
                "The agent exceeded its execution budget. This may indicate a tool loop "
                "or an overly complex task. Review the tools_used list for repeated patterns."
            )
        }

    def run(self, task: str) -> dict:
        self.start_time = time.time()
        self.steps = []

        for step_num in range(self.max_steps + 1):
            budget_error = self._is_budget_exceeded()
            if budget_error:
                return self._generate_partial_result(task, budget_error)

            # Get next action from agent
            action = self.agent.get_next_action(task, self.steps)

            if action.is_final_answer:
                return {"status": "complete", "result": action.answer, "steps_taken": step_num}

            # Execute tool
            result = self.agent.execute_tool(action.tool_name, action.tool_args)
            self.steps.append(AgentStep(
                step_number=step_num,
                tool_name=action.tool_name,
                tool_args=action.tool_args,
                tool_result=result
            ))

        return self._generate_partial_result(task, "Max steps reached")

from collections import deque
from typing import Deque, List, Tuple
import json

class LoopPattern:
    def __init__(self, tool_name: str, args_hash: str, count: int):
        self.tool_name = tool_name
        self.args_hash = args_hash
        self.count = count

class RealTimeLoopDetector:
    def __init__(self, window_size: int = 6, repeat_threshold: int = 2):
        self.window_size = window_size
        self.repeat_threshold = repeat_threshold
        self.call_window: Deque[Tuple[str, str]] = deque(maxlen=window_size)

    def _hash_args(self, args: dict) -> str:
        return json.dumps(args, sort_keys=True)

    def record_call(self, tool_name: str, args: dict):
        self.call_window.append((tool_name, self._hash_args(args)))

    def detect_loops(self) -> List[LoopPattern]:
        """Analyze the current window for loop patterns."""
        patterns = []
        call_counts: dict = {}

        for tool_name, args_hash in self.call_window:
            key = (tool_name, args_hash)
            call_counts[key] = call_counts.get(key, 0) + 1

        for (tool_name, args_hash), count in call_counts.items():
            if count >= self.repeat_threshold:
                patterns.append(LoopPattern(tool_name, args_hash, count))

        return patterns

    def generate_intervention_message(self, patterns: List[LoopPattern]) -> str:
        """Generate a message to inject into the agent's context to break the loop."""
        if not patterns:
            return ""

        tool_names = [p.tool_name for p in patterns]
        message = (
            f"[SYSTEM LOOP DETECTION ALERT] The following tools have been called "
            f"repeatedly with the same arguments in the last {self.window_size} steps: "
            f"{', '.join(tool_names)}. "
            f"This indicates you are in a reasoning loop. "
            f"You MUST take one of the following actions:\n"
            f"1. Use a completely different tool to approach the problem.\n"
            f"2. Modify your goal decomposition — the current subtask may be unsolvable.\n"
            f"3. Return a partial answer explaining what you attempted and why it failed.\n"
            f"Do NOT call {tool_names[0]} again with the same arguments."
        )
        return message


class LoopAwareAgentOrchestrator:
    def __init__(self, agent, detector: RealTimeLoopDetector):
        self.agent = agent
        self.detector = detector

    def run_step(self, task: str, history: list) -> dict:
        # Check for loops before getting next action
        loop_patterns = self.detector.detect_loops()
        intervention = self.detector.generate_intervention_message(loop_patterns)

        # Inject intervention into context if loops detected
        augmented_history = history.copy()
        if intervention:
            augmented_history.append({
                "role": "system",
                "content": intervention
            })

        # Get next action with loop-aware context
        action = self.agent.get_next_action(task, augmented_history)

        # Record the call for future loop detection
        if not action.is_final_answer:
            self.detector.record_call(action.tool_name, action.tool_args)

        return action
